import openai

client = openai.OpenAI()

def build_tdd_prompt(test_source: str, function_signature: str, language: str = "python") -> list[dict]:
    return [
        {
            "role": "system",
            "content": (
                f"You are a {language} developer implementing a function. "
                "Read the provided tests carefully. "
                "Write an implementation that makes every test pass. "
                "Return only the implementation code — no test code, no explanation."
            ),
        },
        {
            "role": "user",
            "content": (
                f"Implement the following function signature:\n"
                f"```{language}\n{function_signature}\n```\n\n"
                f"The implementation must pass these tests:\n"
                f"```{language}\n{test_source}\n```"
            ),
        },
    ]

# Example usage
test_code = """
import pytest
from solution import clamp

def test_within_range():
    assert clamp(5, 0, 10) == 5

def test_below_min():
    assert clamp(-3, 0, 10) == 0

def test_above_max():
    assert clamp(15, 0, 10) == 10

def test_at_min_boundary():
    assert clamp(0, 0, 10) == 0

def test_at_max_boundary():
    assert clamp(10, 0, 10) == 10

def test_invalid_range():
    with pytest.raises(ValueError):
        clamp(5, 10, 0)  # min > max
"""

signature = "def clamp(value: float, min_val: float, max_val: float) -> float:"

resp = client.chat.completions.create(
    model="gpt-4o-mini",
    temperature=0.1,
    messages=build_tdd_prompt(test_code, signature),
)
print(resp.choices[0].message.content)

import subprocess
import json
import ast
from pathlib import Path

def get_uncovered_lines(source_path: str, test_dir: str) -> dict[str, list[int]]:
    """
    Returns {filename: [uncovered_line_numbers]} by running coverage.
    """
    subprocess.run(
        ["python", "-m", "coverage", "run", "--source", source_path,
         "-m", "pytest", test_dir, "-q"],
        capture_output=True, timeout=60,
    )
    subprocess.run(
        ["python", "-m", "coverage", "json", "-o", "/tmp/cov.json"],
        capture_output=True,
    )
    data = json.loads(Path("/tmp/cov.json").read_text())
    result = {}
    for fname, info in data.get("files", {}).items():
        missing = info.get("missing_lines", [])
        if missing:
            result[fname] = missing
    return result

def extract_function_containing_lines(
    source: str, target_lines: list[int]
) -> list[tuple[str, str]]:
    """Returns list of (function_name, function_source) for functions containing target lines."""
    tree = ast.parse(source)
    src_lines = source.splitlines()
    result = []
    for node in ast.walk(tree):
        if not isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            continue
        fn_lines = set(range(node.lineno, node.end_lineno + 1))
        if fn_lines.intersection(target_lines):
            fn_source = "\n".join(src_lines[node.lineno - 1:node.end_lineno])
            result.append((node.name, fn_source))
    return result

def build_coverage_test_prompt(
    function_name: str,
    function_source: str,
    uncovered_lines: list[int],
    existing_tests: str = "",
) -> list[dict]:
    uncovered_str = ", ".join(str(l) for l in uncovered_lines)
    existing_note = (
        f"\n\nExisting tests (do not duplicate):\n```python\n{existing_tests}\n```"
        if existing_tests else ""
    )
    return [
        {
            "role": "system",
            "content": (
                "Write pytest test cases that increase code coverage. "
                "Focus on branches and edge cases, not just the happy path. "
                "Return only the test code."
            ),
        },
        {
            "role": "user",
            "content": (
                f"Write tests for `{function_name}` that cover lines {uncovered_str}. "
                f"These lines are currently not covered by any test.\n\n"
                f"Function:\n```python\n{function_source}\n```"
                f"{existing_note}"
            ),
        },
    ]

def validate_generated_tests(
    generated_test_source: str,
    implementation_source: str,
    module_name: str = "solution",
) -> dict:
    """
    Returns a validation report dict.
    """
    # Check 1: pass on correct implementation
    passed, output = run_tests_against_code(
        implementation_source, generated_test_source, module_name
    )
    if not passed:
        return {"valid": False, "reason": "tests_fail_on_correct_impl", "output": output}

    # Check 2: fail on a trivially broken version (negate first return)
    import re
    broken = re.sub(
        r"(return\s+)(True|False|\d+)",
        lambda m: m.group(1) + ("False" if m.group(2) == "True" else
                                "True" if m.group(2) == "False" else
                                str(int(m.group(2)) + 1)),
        implementation_source,
        count=1,
    )
    if broken == implementation_source:
        # Could not inject a trivial bug; skip this check
        return {"valid": True, "mutation_checked": False}

    fails_on_broken, _ = run_tests_against_code(broken, generated_test_source, module_name)
    if fails_on_broken:  # tests passed even on broken code — they're too weak
        return {"valid": False, "reason": "tests_pass_on_broken_impl"}

    return {"valid": True, "mutation_checked": True}

import subprocess
import re

def get_surviving_mutants(source_path: str, test_path: str) -> list[dict]:
    """
    Runs mutmut and returns surviving mutants as structured dicts.
    Requires: pip install mutmut
    """
    subprocess.run(
        ["mutmut", "run", "--paths-to-mutate", source_path,
         "--tests-dir", test_path],
        capture_output=True, timeout=300,
    )
    result = subprocess.run(
        ["mutmut", "results"], capture_output=True, text=True
    )
    survived = []
    for line in result.stdout.splitlines():
        match = re.match(r"(\d+)\s+", line)
        if match:
            mutant_id = match.group(1)
            diff = subprocess.run(
                ["mutmut", "show", mutant_id], capture_output=True, text=True
            ).stdout
            survived.append({"id": mutant_id, "diff": diff})
    return survived

def build_kill_mutant_prompt(
    mutant_diff: str,
    function_source: str,
    existing_tests: str,
) -> list[dict]:
    return [
        {
            "role": "system",
            "content": (
                "Write a pytest test that passes on the original code "
                "but fails on the mutated version. "
                "Return only the test function."
            ),
        },
        {
            "role": "user",
            "content": (
                f"The following mutation survived (existing tests did not catch it):\n"
                f"```diff\n{mutant_diff}\n```\n\n"
                f"Original function:\n```python\n{function_source}\n```\n\n"
                f"Write a test that kills this mutant. "
                f"Existing tests (do not duplicate):\n```python\n{existing_tests}\n```"
            ),
        },
    ]
